class Solution:
    def getHint(self, secret: str, guess: str) -> str:
        bulls = 0
        count_s = {}
        count_g = {}
        for s, g in zip(secret, guess):
            if s == g:
                bulls += 1
            else:
                count_s[s] = count_s.get(s, 0) + 1
                count_g[g] = count_g.get(g, 0) + 1
        cows = sum(min(count_s.get(d, 0), count_g.get(d, 0)) for d in count_s.keys() & count_g.keys())
        return f"{bulls}A{cows}B"
```

